export interface SubscriptionObject {
    nextErrorId:string;
    subscribedErrorId:string;
    resolved:boolean;
}

export interface ProcessedErrorObject {
    processedError:boolean;
}

export const ErrorStatus: { ABORTED: string, NETWORK_ERROR: string, DATA_ERROR: string };

export function init(service:{host:string; port:string}): void;
export function getCurrentErrorId(callback:(err:Error, currentErrorId:string)=>void): void;
export function getErrorCount(callback:(err:Error, numErrors:number)=>void): void;
export function subscribeError(errorCode:string, callback:(error:Error, subscriptionObj: SubscriptionObject)=>void): void;
export function processedError(errorCode:string, callback:(error:Error, processedErrorObject: ProcessedErrorObject)=>void): void;
